f"""<!DOCTYPE html>
<html lang="tr">
<head><meta charset="utf-8">
<title>J.A.R.V.I.S. V14 Validation Report</title>
<style>
  body {{ font-family: 'Segoe UI', system-ui; max-width: 1000px; margin: 40px auto; padding: 20px; background: #0a0f1e; color: #c8d8f0; }}
  h1 {{ color: #00c8ff; font-weight: 300; border-bottom: 2px solid #00c8ff; padding-bottom: 10px; }}
  h2 {{ color: #7fc8ff; border-bottom: 1px solid #1a3a5c; padding-bottom: 6px; margin-top: 40px; }}
  .score-card {{ display: flex; align-items: center; justify-content: space-between; background: #0e1a2e; border: 1px solid #1a3a5c; border-radius: 8px; padding: 20px; margin: 20px 0; }}
  .score {{ font-size: 4em; color: #00e87a; font-weight: bold; line-height: 1; }}
  .score-meta {{ font-size: 1.2em; color: #8ab4f8; }}
  .card {{ background: #0e1a2e; border: 1px solid #1a3a5c; border-radius: 8px; padding: 20px; margin: 16px 0; position: relative; overflow: hidden; }}
  .card::before {{ content: ''; position: absolute; left: 0; top: 0; bottom: 0; width: 4px; }}
  .card.pass::before {{ background: #00e87a; }}
  .card.fail::before, .card.error::before {{ background: #ff4444; }}
  .card.partial::before {{ background: #ffd700; }}
  .PASS {{ color: #00e87a; font-weight: bold; }} .PARTIAL {{ color: #ffd700; font-weight: bold; }} .FAIL {{ color: #ff4444; font-weight: bold; }} .ERROR {{ color: #ff6b35; font-weight: bold; }} .SKIPPED {{ color: #888; font-weight: bold; }}
  table {{ width: 100%; border-collapse: collapse; margin-top: 10px; }}
  th, td {{ padding: 12px 16px; border-bottom: 1px solid #1a3a5c; text-align: left; }}
  th {{ color: #7fc8ff; font-weight: 600; background: #081121; }}
  tr:hover {{ background: #132238; }}
  pre {{ background: #060b14; padding: 15px; border-radius: 6px; overflow-x: auto; font-size: 13px; color: #a0b8d0; border: 1px solid #14243b; }}
  .bar {{ background: #1a3a5c; border-radius: 4px; height: 10px; overflow: hidden; }}
  .bar-fill {{ background: linear-gradient(90deg, #00c8ff, #00e87a); border-radius: 4px; height: 10px; }}
  .diagnostic {{ margin-top: 15px; padding: 15px; border-radius: 6px; background: rgba(0, 200, 255, 0.05); border: 1px solid rgba(0, 200, 255, 0.2); }}
  .diagnostic.success {{ background: rgba(0, 232, 122, 0.05); border-color: rgba(0, 232, 122, 0.2); }}
  .diagnostic.danger {{ background: rgba(255, 68, 68, 0.05); border-color: rgba(255, 68, 68, 0.2); }}
  .diag-title {{ font-weight: bold; margin-bottom: 8px; display: flex; align-items: center; gap: 8px; }}
  .diag-title.success {{ color: #00e87a; }}
  .diag-title.danger {{ color: #ff4444; }}
</style>
</head>
<body>
<h1>🤖 J.A.R.V.I.S. V14 — Bilişsel Doğrulama Raporu</h1>
<p style="color: #8ab4f8;">Oluşturulma: {report['timestamp']} | Toplam Süre: {report['total_time_s']}s</p>
<div class="score-card">
  <div>
    <div class="score">{report['overall_score']:.2f}<span style="font-size:.4em; color:#7fc8ff">/1.00</span></div>
    <div class="score-meta">Genel Sistem Kararlılık Skoru</div>
  </div>
  <div style="text-align: right;">
    <div style="font-size: 1.2em; margin-bottom: 8px;">
      <span class="PASS">✓ {report['summary']['passed']} Başarılı</span> | 
      <span class="FAIL">✗ {report['summary']['failed']} Başarısız</span>
    </div>
    <div style="color: #8ab4f8;">
      Hatalar: {report['summary']['errors']} | Atlananlar: {report['summary']['skipped']}
    </div>
  </div>
</div>
<h2>📌 Özet Tablosu</h2>
<table>
<tr><th>Test Modülü</th><th>Durum</th><th>Skor</th><th>Başarı Oranı</th></tr>
"""

